import React from 'react';
import { Pressable, SafeAreaView, ScrollView, StyleSheet, Text, View } from 'react-native';
import AppIcon from '../components/AppIcon';
import CustomerBottomNav from '../components/CustomerBottomNav';
import ScreenHeader from '../components/ScreenHeader';
import { createShadow } from '../styles/shadows';
import { theme } from '../styles/theme';

const balance = 40;
const rechargeOptions = ['Rs100', 'Rs200', 'Rs500', 'Rs1000'];

const transactions = [
  { id: 'tx1', title: 'Wallet Recharge', type: 'credit', date: '14 Apr 2026', amount: '+ Rs500', status: 'Success' },
  { id: 'tx2', title: 'Order Payment', type: 'debit', date: '13 Apr 2026', amount: '- Rs120', status: 'Paid' },
  { id: 'tx3', title: 'Wallet Recharge', type: 'credit', date: '11 Apr 2026', amount: '+ Rs200', status: 'Success' },
  { id: 'tx4', title: 'Order Payment', type: 'debit', date: '10 Apr 2026', amount: '- Rs40', status: 'Pending' }
];

const paymentMethods = [
  { id: 'pm1', title: 'UPI', subtitle: 'Fast recharge with any UPI app', icon: 'phone-portrait-outline' },
  { id: 'pm2', title: 'Card', subtitle: 'Credit or debit card payment', icon: 'card-outline' },
  { id: 'pm3', title: 'Net Banking', subtitle: 'Direct payment from your bank', icon: 'business-outline' }
];

const statusTone = (status: string) => {
  switch (status) {
    case 'Success':
    case 'Paid':
      return { badge: styles.statusSuccess, text: styles.statusTextSuccess };
    case 'Pending':
      return { badge: styles.statusPending, text: styles.statusTextPending };
    default:
      return { badge: styles.statusNeutral, text: styles.statusTextNeutral };
  }
};

const CustomerWalletScreen = () => {
  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        <ScreenHeader
          title="Wallet"
          subtitle="A brighter iPhone-style wallet with balance, recharge shortcuts, payments, and transaction history."
        />

        <View style={styles.balanceCard}>
          <View style={styles.balanceTopRow}>
            <View>
              <Text style={styles.balanceLabel}>Current wallet balance</Text>
              <Text style={styles.balanceValue}>Rs {balance}</Text>
            </View>
            <View style={styles.balanceIcon}>
              <AppIcon name="wallet-outline" size={22} color={theme.colors.primary} />
            </View>
          </View>
          <Text style={styles.balanceHint}>Use wallet balance for faster checkout during order confirmation.</Text>
        </View>

        {balance < 50 ? (
          <View style={styles.warningCard}>
            <AppIcon name="warning-outline" size={18} color={theme.colors.warning} />
            <View style={styles.warningBody}>
              <Text style={styles.warningTitle}>Low balance</Text>
              <Text style={styles.warningText}>Your wallet is below Rs 50. Add money before the next order.</Text>
            </View>
          </View>
        ) : null}

        <View style={styles.card}>
          <View style={styles.cardHeader}>
            <Text style={styles.sectionTitle}>Add money</Text>
            <AppIcon name="add-circle-outline" size={18} color={theme.colors.primary} />
          </View>
          <Text style={styles.sectionSubtitle}>Pick a quick recharge amount</Text>
          <View style={styles.rechargeGrid}>
            {rechargeOptions.map((amount) => (
              <Pressable key={amount} style={styles.amountChip}>
                <Text style={styles.amountChipText}>{amount}</Text>
              </Pressable>
            ))}
          </View>
          <Pressable style={styles.primaryButton}>
            <AppIcon name="arrow-up-circle-outline" size={18} color="#fff" />
            <Text style={styles.primaryButtonText}>Add money</Text>
          </Pressable>
        </View>

        <View style={styles.card}>
          <View style={styles.cardHeader}>
            <Text style={styles.sectionTitle}>Pay for order</Text>
            <AppIcon name="cash-outline" size={18} color={theme.colors.secondary} />
          </View>
          <Text style={styles.sectionSubtitle}>Use available balance instead of cash on delivery.</Text>
          <View style={styles.payCard}>
            <Text style={styles.payLabel}>Available to spend</Text>
            <Text style={styles.payValue}>Rs {balance}</Text>
            <Pressable style={styles.secondaryButton}>
              <AppIcon name="checkmark-circle-outline" size={18} color={theme.colors.primary} />
              <Text style={styles.secondaryButtonText}>Pay for order</Text>
            </Pressable>
          </View>
        </View>

        <View style={styles.card}>
          <View style={styles.cardHeader}>
            <Text style={styles.sectionTitle}>Transaction history</Text>
            <AppIcon name="time-outline" size={18} color={theme.colors.textSecondary} />
          </View>
          {transactions.map((transaction) => {
            const tone = statusTone(transaction.status);
            const isCredit = transaction.type === 'credit';

            return (
              <View key={transaction.id} style={styles.transactionRow}>
                <View style={[styles.transactionIcon, isCredit ? styles.creditIcon : styles.debitIcon]}>
                  <AppIcon
                    name={isCredit ? 'arrow-down-outline' : 'arrow-up-outline'}
                    size={18}
                    color={isCredit ? theme.colors.secondary : theme.colors.danger}
                  />
                </View>
                <View style={styles.transactionBody}>
                  <Text style={styles.transactionTitle}>{transaction.title}</Text>
                  <Text style={styles.transactionDate}>{transaction.date}</Text>
                </View>
                <View style={styles.transactionRight}>
                  <Text style={styles.transactionAmount}>{transaction.amount}</Text>
                  <View style={[styles.statusBadge, tone.badge]}>
                    <Text style={[styles.statusText, tone.text]}>{transaction.status}</Text>
                  </View>
                </View>
              </View>
            );
          })}
        </View>

        <View style={styles.card}>
          <View style={styles.cardHeader}>
            <Text style={styles.sectionTitle}>Payment methods</Text>
            <AppIcon name="card-outline" size={18} color={theme.colors.textSecondary} />
          </View>
          {paymentMethods.map((method) => (
            <View key={method.id} style={styles.methodRow}>
              <View style={styles.methodIcon}>
                <AppIcon name={method.icon} size={18} color={theme.colors.primary} />
              </View>
              <View style={styles.methodBody}>
                <Text style={styles.methodTitle}>{method.title}</Text>
                <Text style={styles.methodSubtitle}>{method.subtitle}</Text>
              </View>
            </View>
          ))}
        </View>
      </ScrollView>
      <CustomerBottomNav active="CustomerWallet" />
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: theme.colors.background
  },
  content: {
    paddingHorizontal: 18,
    paddingTop: 18,
    paddingBottom: 110
  },
  balanceCard: {
    borderRadius: 30,
    padding: 22,
    backgroundColor: '#EDF5FF',
    borderWidth: 1,
    borderColor: '#D7E5FF'
  },
  balanceTopRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center'
  },
  balanceLabel: {
    color: theme.colors.textSecondary,
    fontSize: 13,
    fontWeight: '700'
  },
  balanceValue: {
    marginTop: 8,
    color: theme.colors.text,
    fontSize: 34,
    fontWeight: '900'
  },
  balanceIcon: {
    width: 50,
    height: 50,
    borderRadius: 25,
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: 'rgba(255,255,255,0.9)'
  },
  balanceHint: {
    marginTop: 14,
    color: theme.colors.textSecondary,
    fontSize: 14,
    lineHeight: 21
  },
  warningCard: {
    marginTop: 14,
    flexDirection: 'row',
    gap: 10,
    borderRadius: 22,
    padding: 16,
    backgroundColor: '#FFF8EA',
    borderWidth: 1,
    borderColor: '#FFE1A6'
  },
  warningBody: {
    flex: 1
  },
  warningTitle: {
    color: '#9A5B00',
    fontSize: 15,
    fontWeight: '800'
  },
  warningText: {
    marginTop: 4,
    color: '#9A5B00',
    fontSize: 13,
    lineHeight: 19
  },
  card: {
    marginTop: 14,
    borderRadius: 28,
    padding: 20,
    backgroundColor: theme.colors.surface,
    borderWidth: 1,
    borderColor: theme.colors.stroke,
    ...createShadow({ color: '#163456', opacity: 0.08, radius: 16, elevation: 5 })
  },
  cardHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center'
  },
  sectionTitle: {
    color: theme.colors.text,
    fontSize: 20,
    fontWeight: '800'
  },
  sectionSubtitle: {
    marginTop: 6,
    color: theme.colors.textSecondary,
    fontSize: 13,
    lineHeight: 20
  },
  rechargeGrid: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 10,
    marginTop: 14
  },
